type InMemoryRaftLog struct {
	// Protects access to all fields. Most methods of InMemoryRaftLog are
	// run on the raft goroutine, but Append() is run on an application
	// goroutine.
	sync.Mutex

	hardState pb.HardState
	snapshot  pb.Snapshot
	// ents[i] has raft log position i+snapshot.Metadata.Index
	ents []pb.Entry

	callStats inMemStorageCallStats
}

// NewInMemoryRaftLog creates an empty InMemoryRaftLog.
func NewInMemoryRaftLog() *InMemoryRaftLog {
	return &InMemoryRaftLog{
		// When starting from scratch populate the list with a dummy entry at term zero.
		ents: make([]pb.Entry, 1),
	}
}

// InitialState implements the Storage interface.
func (ms *InMemoryRaftLog) InitialState() (pb.HardState, pb.ConfState, error) {
	ms.callStats.initialState++
	return ms.hardState, ms.snapshot.Metadata.ConfState, nil
}

